POST /api/v1/user/profile/settings HTTP/1.1
Host: config-sync-platform.io
Authorization: Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1c2VyX2lkIjoiNzg5MzQifQ.c2lnbmF0dXJlMTIzNDU2
Content-Type: application/json
Accept: application/json
Connection: keep-alive
User-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/115.0.0.0 Safari/537.36

{
  "preferences": {
    "notifications": {
      "email": true,
      "sms": false,
      "push": {
        "enabled": true,
        "sound": "chime",
        "categories": ["news", "alerts", "updates"]
      }
    },
    "theme": {
      "current": "dark",
      "available": ["light", "dark", "solarized"]
    }
  },
  "privacy": {
    "profile_visibility": "friends",
    "data_sharing": {
      "analytics": false,
      "third_party": ["serviceA", "serviceB"],
      "user_consent": true
    }
  }
}

PUT /api/v5/dashboard/widgets/31415/config HTTP/1.1
Host: analytics-dashboard.app
Content-Type: application/json
Accept: application/json
Authorization: Token cffea6d2a19247f3b204180d9133dc19
User-Agent: Mozilla/5.0 (Linux; Android 12; Pixel 5a) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/108.0.5359.128 Mobile Safari/537.36
Connection: keep-alive
Content-Length: 342

{
  "widgetId": 31415,
  "configuration": {
    "display": {
      "type": "time-series",
      "theme": "light",
      "refreshInterval": 30000
    },
    "dataSources": [
      {"source": "metrics_api", "queries": ["avg_cpu", "max_memory"]},
      {"source": "user_events", "filters": {"eventType": ["login", "purchase"]}}
    ],
    "alerts": [{"threshold": 80, "metric": "cpu", "condition": "above"}]
  }
}

