POST /api/v5/device/configure HTTP/1.1
Host: smart-home-controls.cloud
Authorization: Bearer bTxD3VmkF98rypvLqAZCNWTXx7scNLzU
Content-Type: application/json
Accept: application/json
User-Agent: Mozilla/5.0 (Linux; Android 13; SM-G991B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/114.0.5735.51 Mobile Safari/537.36
Content-Length: 365

{
  "deviceId": "SHD-99384",
  "config": {
    "modes": ["eco", "comfort", "away"],
    "sensors": {
      "temperature": {
        "calibration": -0.3,
        "units": "Celsius",
        "thresholds": {"min": 16, "max": 28}
      },
      "humidity": {
        "calibration": 0.5,
        "thresholds": {"min": 30, "max": 60}
      }
    },
    "schedule": [
      {"day": "monday", "start": "06:00", "end": "22:00"},
      {"day": "tuesday", "start": "06:00", "end": "22:00"}
    ]
  }
}

